      editor.zoomToFit({ animation: { duration: 0 } })

      if (pdf.numPages <= INITIAL_PAGES) return

      let debounceTimer: ReturnType<typeof setTimeout> | null = null

      unsubscribe = editor.store.listen(() => {
        if (debounceTimer) clearTimeout(debounceTimer)
        debounceTimer = setTimeout(() => {
          const vp = editor.getViewportPageBounds()
          for (let i = INITIAL_PAGES; i < layout.length; i++) {
            if (renderedPages.has(i)) continue
            const page = layout[i]!
            // Check if page bounds intersect the viewport
            if (
              page.x < vp.maxX &&
              page.x + page.w > vp.minX &&
              page.y < vp.maxY &&
              page.y + page.h > vp.minY
            ) {
              renderAndCreate(i)
            }
          }
        }, 150)
      })
    }

    init()

    return () => {
      unsubscribe?.()
    }
  }, [editor, bytes])

  return null
}

